const body = $json.body ?? $json;
const rawType = (body.type ?? 'unknown').toString().toLowerCase();
const allowed = ['chat_message', 'auth_signup', 'auth_login', 'seed_selected', 'course_proposal', 'course_vote'];
const eventType = allowed.includes(rawType) ? rawType : 'unknown';

let priority = 'low';
if (eventType === 'auth_signup' || eventType === 'course_proposal') priority = 'medium';
if (eventType === 'unknown') priority = 'high';

return [{
  json: {
    status: 'accepted',
    session: 'system',
    eventType,
    priority,
    receivedAt: new Date().toISOString(),
    audit: {
      userName: body.userName ?? body.email ?? 'anonymous',
      room: body.room ?? null,
      messageId: body.messageId ?? null
    },
    raw: body
  }
}];
